NP_functionality.VERILOG_PROVIDED:
assign done = r[0] && r[1] && br;
assign reg_out[0] = (br && ~r[0]) | (~br && r[0]);
assign reg_out[1] = ((br && r[0] && ~r[1]) || (br && r[1] && ~r[0])) | (~br && r[1]);

reg [PORTSIZE_kmp_bambu_barrier_reached_we - 1 : 0] barrier_done;
wire [PORTSIZE_kmp_bambu_barrier_reached_we - 1 : 0] barrier_done_next;
wire [PORTSIZE_kmp_bambu_barrier_reached_we - 1 : 0] barrier_done_update;
wire register_reset;

always @(posedge clock) 
begin	
   if(1RESET_VALUE)
   begin
      barrier_done <= 0;
   end
   else if(register_reset)
   begin
      barrier_done <= 0;
   end
   else
   begin
      barrier_done <= barrier_done_next;
   end
end

generate
   genvar i;

   if(CONTEXT_NUMBER == 1)
   begin
      assign barrier_done_update = kmp_bambu_barrier_reached_we;
   end
   else 
   begin

      reg [PORTSIZE_kmp_bambu_barrier_reached_we * TID_BITSIZE-1:0] register;
      wire [PORTSIZE_kmp_bambu_barrier_reached_we * TID_BITSIZE-1:0] register_next;

      always @(posedge clock) 
      begin	
         if(1RESET_VALUE)
         begin
            register <= 0;
         end
         else if(register_reset)
         begin
            register <= 0;
         end
         else
         begin
            register <= register_next;
         end
      end

      if(CONTEXT_NUMBER == 2)
      begin

         for(i = 0; i < PORTSIZE_kmp_bambu_barrier_reached_we; i = i + 1)
         begin : add
            barrier_manager_internal_adder_2 adder (.r(register[i]),
            .reg_out(register_next[i]),
            .br(kmp_bambu_barrier_reached_we[i]),
            .done(barrier_done_update[i]));
         end

      end
      else if(CONTEXT_NUMBER == 4)
      begin

         for(i = 0; i < PORTSIZE_kmp_bambu_barrier_reached_we; i = i + 1)
         begin : add
            barrier_manager_internal_adder_4 adder (.r(register[i*2 +: 2]),
            .reg_out(register_next[i*2 +: 2]),
            .br(kmp_bambu_barrier_reached_we[i]),
            .done(barrier_done_update[i]));
         end

      end
      else if(CONTEXT_NUMBER == 8)
      begin

         for(i = 0; i < PORTSIZE_kmp_bambu_barrier_reached_we; i = i + 1)
         begin : add
            barrier_manager_internal_adder_8 adder (.r(register[i*3 +: 3]),
            .reg_out(register_next[i*3 +: 3]),
            .br(kmp_bambu_barrier_reached_we[i]),
            .done(barrier_done_update[i]));
         end

      end
      else if(CONTEXT_NUMBER == 16)
      begin

         for(i = 0; i < PORTSIZE_kmp_bambu_barrier_reached_we; i = i + 1)
         begin : add
            barrier_manager_internal_adder_16 adder (.r(register[i*4 +: 4]),
            .reg_out(register_next[i*4 +: 4]),
            .br(kmp_bambu_barrier_reached_we[i]),
            .done(barrier_done_update[i]));
         end

      end
      else
      begin

         for(i = 0; i < PORTSIZE_kmp_bambu_barrier_reached_we; i = i + 1)
         begin : add
            barrier_manager_internal_adder #(.BITSIZE_r(TID_BITSIZE),
            .BITSIZE_reg_out(TID_BITSIZE)) adder (.r(register[i*TID_BITSIZE +: TID_BITSIZE]),
            .reg_out(register_next[i*TID_BITSIZE +: TID_BITSIZE]),
            .br(kmp_bambu_barrier_reached_we[i]),
            .done(barrier_done_update[i]));
         end

      end
   end
endgenerate

assign barrier_done_next = barrier_done | barrier_done_update;

assign register_reset = &barrier_done;
assign kmp_bambu_wait_all_threads_rd = &barrier_done;

`ifndef CLOG2
`define CLOG2(x) \
  (x <= 2) ? 1 : \
  (x <= 4) ? 2 : \
  (x <= 8) ? 3 : \
  (x <= 16) ? 4 : \
  (x <= 32) ? 5 : \
  (x <= 64) ? 6 : \
  (x <= 128) ? 7 : \
  (x <= 256) ? 8 : \
  -1
`endif

localparam REG_SIZE = CONTEXT_NUMBER > 1 ? CONTEXT_NUMBER * PORTSIZE_kmp_lock_acquired : PORTSIZE_kmp_lock_acquired;
localparam REG_BITSIZE = `CLOG2(REG_SIZE);
localparam CONTEXT_NUMBER_BITSIZE = `CLOG2(CONTEXT_NUMBER);
localparam ACCELERATOR_NUMBER_BITSIZE = `CLOG2(ACCELERATOR_NUMBER);

reg [REG_SIZE - 1:0] lock_request_reg;
wire [REG_SIZE -1:0] lock_request_next, lock_request_delete;
reg lock_free_reg;
wire lock_free_next;
wire [REG_BITSIZE-1:0] request_selected;
wire request_empty;

always @(posedge clock) 
begin	
   if(1RESET_VALUE)
   begin
      lock_request_reg <= 0;
      lock_free_reg <= 1;
   end
   else 
   begin
      lock_request_reg <= lock_request_next;
      lock_free_reg <= lock_free_next;
   end
end

generate
   if(USE_CS)
   begin
      genvar i; 
      for (i = 0; i < PORTSIZE_kmp_lock_acquired; i = i + 1)
      begin 
         assign lock_request_next[i*CONTEXT_NUMBER +: CONTEXT_NUMBER] = (kmp_lock_acquired[i] ? (lock_request_reg[i*CONTEXT_NUMBER +: CONTEXT_NUMBER] | (1 << kmp_lock_acquired_tag[i*BITSIZE_kmp_lock_acquired_tag +: BITSIZE_kmp_lock_acquired_tag])) :  lock_request_reg[i*CONTEXT_NUMBER +: CONTEXT_NUMBER]) & ~lock_request_delete[i*CONTEXT_NUMBER +: CONTEXT_NUMBER];
      end
   end
   else
   begin
      assign lock_request_next = (lock_request_reg | kmp_lock_acquired) & ~lock_request_delete;
   end
endgenerate

generate
  if(REG_SIZE == 2)
  begin
    multiple_priority_encoder_2_1 encoder (.empty(request_empty),
      .i(lock_request_reg),
      .o(request_selected));
  end
  else if(REG_SIZE == 4)
  begin
    multiple_priority_encoder_4_2 encoder (.empty(request_empty),
      .i(lock_request_reg),
      .o(request_selected));
  end
  else if(REG_SIZE == 8)
  begin
    multiple_priority_encoder_8_3 encoder (.empty(request_empty),
      .i(lock_request_reg),
      .o(request_selected));
  end
  else if(REG_SIZE == 16)
  begin
    multiple_priority_encoder_16_4 encoder (.empty(request_empty),
      .i(lock_request_reg),
      .o(request_selected));
  end
  else if(REG_SIZE == 32)
  begin
    multiple_priority_encoder_32_5 encoder (.empty(request_empty),
      .i(lock_request_reg),
      .o(request_selected));
  end
  else if(REG_SIZE == 64)
  begin
    multiple_priority_encoder_64_6 encoder (.empty(request_empty),
      .i(lock_request_reg),
      .o(request_selected));
  end
  else
  begin
    // synthesis translate_off
    $fatal;
    // synthesis translate_on
  end
endgenerate

assign lock_request_delete = lock_free_reg & ~request_empty ? 1 << request_selected : 0;
assign lock_free_next = (lock_free_reg & request_empty) | (|kmp_lock_release);

generate
   if(USE_CS)
   begin
      assign kmp_lock_acquired_ack = lock_free_reg & ~request_empty ? (1 << request_selected[ACCELERATOR_NUMBER_BITSIZE+CONTEXT_NUMBER_BITSIZE-1:CONTEXT_NUMBER_BITSIZE]) : 0;
      genvar j;
      for(j=0; j < PORTSIZE_kmp_lock_acquired_ack_tag; j = j + 1)
      begin
         assign kmp_lock_acquired_ack_tag[j*BITSIZE_kmp_lock_acquired_ack_tag+:BITSIZE_kmp_lock_acquired_ack_tag] = lock_free_reg & ~request_empty ? request_selected[CONTEXT_NUMBER_BITSIZE-1:0] : 0;
      end
   end
   else
   begin
      assign kmp_lock_acquired_ack = lock_free_reg & ~request_empty ? (1 << request_selected) : 0;
      assign kmp_lock_acquired_ack_tag = 0;
   end
endgenerate

assign o[0] = d || (wa && ~l);
assign o[1] =(l || wa) && ~d;
assign valid = d || l || wa;

reg [2*THREAD_NUMBER-1:0] cs_thread_answer_type_reg;
wire [2*THREAD_NUMBER-1:0] cs_thread_answer_type_reg_next;
wire [2*THREAD_NUMBER-1:0] cs_thread_answer_type_map_output;
wire [THREAD_NUMBER-1:0] cs_thread_answer_type_map_valid;
reg [THREAD_NUMBER*BITSIZE_M_Rdata_ram-1:0] M_Rdata_ram_reg;
wire [THREAD_NUMBER*BITSIZE_M_Rdata_ram-1:0] M_Rdata_ram_reg_next;
reg [THREAD_NUMBER-1:0] thread_ready;
wire [THREAD_NUMBER-1:0] thread_ready_next;
wire [THREAD_NUMBER-1:0] thread_ready_wait_all;
wire [THREAD_NUMBER-1:0] thread_ready_datardy;
wire [THREAD_NUMBER-1:0] thread_ready_lock;
reg [THREAD_NUMBER_SIZE-1 :0] current_tid;
wire [THREAD_NUMBER_SIZE-1 :0] next_tid;
wire [THREAD_NUMBER_SIZE-1 :0] new_tid;
wire [THREAD_NUMBER-1:0] thread_delete;
reg started;
wire started_next;
reg thread_ready_empty;
wire thread_ready_empty_next;

wire cs_condition;
reg cs_condition_reg;
wire cs_condition_reg_next;
wire cs_thread_ready_valid;
wire cs_next;

genvar i;

always @(posedge clock)
begin
   if(1RESET_VALUE)
   begin
      started <= 0;
   end
   else 
   begin
      started <= started_next;
   end
end

assign started_next = (component_done == 1) ? 0 : ((start_port == 1) ? 1 : started);

always @(posedge clock) 
begin	
   if(1RESET_VALUE || start_port == 1)
   begin
      M_Rdata_ram_reg <= 0;
      current_tid <= 0;
      thread_ready <= (1 << THREAD_NUMBER) - 2;
      thread_ready_empty <= 0;
      cs_condition_reg <= 0;
      cs_thread_answer_type_reg <= 0;
   end
   else
   begin 
      M_Rdata_ram_reg <= M_Rdata_ram_reg_next;
      current_tid <= next_tid;
      thread_ready <= thread_ready_next;
      thread_ready_empty <= thread_ready_empty_next;
      cs_condition_reg <= cs_condition_reg_next;
      cs_thread_answer_type_reg <= cs_thread_answer_type_reg_next;
   end
end

generate
   for(i = 0; i < THREAD_NUMBER; i = i + 1)
   begin : im
      cs_manager_internal_map map (.l(thread_ready_lock[i]),
      .d(thread_ready_datardy[i]),
      .wa(thread_ready_wait_all[i]),
      .o(cs_thread_answer_type_map_output[2*i+:2]),
      .valid(cs_thread_answer_type_map_valid[i]));


      assign cs_thread_answer_type_reg_next[2*i+:2] = cs_thread_answer_type_map_valid[i] ? cs_thread_answer_type_map_output[2*i+:2] : cs_thread_answer_type_reg[2*i+:2];
      assign M_Rdata_ram_reg_next[i*BITSIZE_M_Rdata_ram +: BITSIZE_M_Rdata_ram] = (M_DataRdy_in && started && selector_register_file_in == i) ? M_Rdata_ram_in : M_Rdata_ram_reg[i*BITSIZE_M_Rdata_ram +: BITSIZE_M_Rdata_ram];
   end
endgenerate

generate
   if(THREAD_NUMBER == 2)
   begin
      multiple_priority_encoder_2_1 encoder (.empty(thread_ready_empty_next),
      .i(thread_ready),
      .o(new_tid));
   end
   else if(THREAD_NUMBER == 4)
   begin
      multiple_priority_encoder_4_2 encoder (.empty(thread_ready_empty_next),
      .i(thread_ready),
      .o(new_tid));
   end
   else if(THREAD_NUMBER == 8)
   begin
      multiple_priority_encoder_8_3 encoder (.empty(thread_ready_empty_next),
      .i(thread_ready),
      .o(new_tid));
   end
   else
   begin
      // synthesis translate_off
      $fatal;
      // synthesis translate_on
   end
endgenerate

assign cs_condition = Mout_oe_ram || Mout_we_ram || kmp_lock_acquired || kmp_bambu_wait_all_threads_ld || done_port;
assign cs_condition_reg_next = (cs_condition || cs_condition_reg) && ~cs_next;
assign cs_thread_ready_valid = (cs_condition || cs_condition_reg) && (thread_ready_empty && ~thread_ready_empty_next);
assign cs_next = (cs_condition && ~thread_ready_empty_next) || cs_thread_ready_valid;

assign thread_ready_datardy = (M_DataRdy_in & started) ? 1 << selector_register_file_in : 0;
assign thread_ready_lock = (kmp_lock_acquired_ack_in & started) ? 1 << kmp_lock_acquired_ack_tag : 0;
assign thread_ready_wait_all = (kmp_bambu_wait_all_threads_rd_in & started) ? {THREAD_NUMBER{1'b1}} : 0;
assign thread_ready_next = (thread_ready | thread_ready_datardy | thread_ready_wait_all | thread_ready_lock) & ~thread_delete;

assign thread_delete = cs_next ? 1 << new_tid : 0;

assign next_tid = cs_next ? new_tid : current_tid;

reg M_DataRdy_out_reg;
wire M_DataRdy_out_reg_next;
reg [BITSIZE_M_Rdata_ram-1:0] M_Rdata_ram_out_reg;
wire [BITSIZE_M_Rdata_ram-1:0] M_Rdata_ram_out_reg_next;
reg kmp_bambu_wait_all_threads_rd_out_reg;
wire kmp_bambu_wait_all_threads_rd_out_reg_next;
reg kmp_lock_acquired_ack_out_reg;
wire kmp_lock_acquired_ack_out_reg_next;

always @(posedge clock) 
begin	
   if(1RESET_VALUE)
   begin
      M_DataRdy_out_reg <= 0;
      M_Rdata_ram_out_reg <= 0;
      kmp_lock_acquired_ack_out_reg <= 0;
      kmp_bambu_wait_all_threads_rd_out_reg <= 0;
   end
   else
   begin 
      M_DataRdy_out_reg <= M_DataRdy_out_reg_next ;
      M_Rdata_ram_out_reg <= M_Rdata_ram_out_reg_next;
      kmp_lock_acquired_ack_out_reg <= kmp_lock_acquired_ack_out_reg_next;
      kmp_bambu_wait_all_threads_rd_out_reg <= kmp_bambu_wait_all_threads_rd_out_reg_next;
   end
end


assign M_DataRdy_out_reg_next = cs_next && cs_thread_answer_type_reg[2*new_tid+:2] == 2'b01;
assign M_Rdata_ram_out_reg_next = cs_next ? M_Rdata_ram_reg[new_tid*BITSIZE_M_Rdata_ram+:BITSIZE_M_Rdata_ram] : 0;
assign kmp_lock_acquired_ack_out_reg_next = cs_next && cs_thread_answer_type_reg[2*new_tid+:2] == 2'b10;
assign kmp_bambu_wait_all_threads_rd_out_reg_next = cs_next && cs_thread_answer_type_reg[2*new_tid+:2] == 2'b11;

assign selector_register_file = current_tid;
assign M_DataRdy = M_DataRdy_out_reg;
assign M_Rdata_ram = M_Rdata_ram_out_reg;
assign kmp_lock_acquired_ack = kmp_lock_acquired_ack_out_reg;
assign  kmp_bambu_wait_all_threads_rd =  kmp_bambu_wait_all_threads_rd_out_reg;

reg [THREAD_NUMBER-1:0] done_reg;
reg [THREAD_NUMBER-1:0] done_reg_next;
wire done_status;

always @(posedge clock 1RESET_EDGE) 
begin
   if (1RESET_VALUE || done_status == 1)
   begin
      done_reg <= {THREAD_NUMBER{1'b0}};
   end
   else
   begin
      done_reg <= done_reg_next;
   end
end

always @(*) 
begin
   done_reg_next = done_reg;
   if (done_port_in == 1)
   begin
      done_reg_next[selector_register_file] = 1'b1;
   end
end

assign done_status = &done_reg;
assign done_port = &done_reg;

reg [THREAD_NUMBER-1:0] start_reg;
reg [THREAD_NUMBER-1:0] start_reg_next;
reg started;
reg started_next;

always @(posedge clock 1RESET_EDGE) 
begin
   if (1RESET_VALUE)
   begin
      start_reg <= {THREAD_NUMBER{1'b0}};
      started <= 1'b0;
   end
   else if(start_port == 1)
   begin
      start_reg <= {THREAD_NUMBER{1'b1}};
      started <= 1'b1;
   end
   else
   begin
      start_reg <= start_reg_next;
      started <= started_next;
   end
end

always @(*)
begin
   started_next = started; 
   if(component_done == 1)
   begin
      started_next = 0;
   end
end

always @(*) 
begin
   start_reg_next = start_reg;
   if (start_reg[selector_register_file] == 1 && started_next)
   begin
      start_reg_next[selector_register_file] = 1'b0;
   end
end

assign start_port_out = start_reg[selector_register_file]  && started_next;

reg [THREAD_NUMBER*BITSIZE_kmp_bambu_set_th_local_reduce_data_val-1:0] base_addr;          
reg [THREAD_NUMBER*BITSIZE_kmp_bambu_set_th_local_reduce_data_val-1:0] base_addr_next;
reg [PORTSIZE_kmp_bambu_get_th_local_reduce_data_ack-1:0] kmp_bambu_get_th_local_reduce_data_ack_reg;
reg [PORTSIZE_kmp_bambu_get_th_local_reduce_data_ack-1:0] kmp_bambu_get_th_local_reduce_data_ack_old;
reg [PORTSIZE_kmp_bambu_set_th_local_reduce_data_ack-1:0] kmp_bambu_set_th_local_reduce_data_ack_reg;
reg [PORTSIZE_kmp_bambu_set_th_local_reduce_data_ack-1:0] kmp_bambu_set_th_local_reduce_data_ack_old;
reg [PORTSIZE_kmp_bambu_get_th_local_reduce_data_val*BITSIZE_kmp_bambu_get_th_local_reduce_data_val-1:0] kmp_bambu_get_th_local_reduce_data_val_reg;
reg [PORTSIZE_kmp_bambu_get_th_local_reduce_data_val*BITSIZE_kmp_bambu_get_th_local_reduce_data_val-1:0] kmp_bambu_get_th_local_reduce_data_val_old;
integer i,j;   

always @(*) 
begin
   base_addr_next = base_addr;
   for (j=0; j < PORTSIZE_kmp_bambu_set_th_local_reduce_data_we; j = j + 1)
   begin
   if(kmp_bambu_set_th_local_reduce_data_we[j] == 1)
   begin
      base_addr_next = base_addr_next | (kmp_bambu_set_th_local_reduce_data_val[j*BITSIZE_kmp_bambu_set_th_local_reduce_data_val +: BITSIZE_kmp_bambu_set_th_local_reduce_data_val] << kmp_bambu_set_th_local_reduce_data_tid[j*BITSIZE_kmp_bambu_set_th_local_reduce_data_tid +: BITSIZE_kmp_bambu_set_th_local_reduce_data_tid]*BITSIZE_kmp_bambu_set_th_local_reduce_data_val);
      kmp_bambu_set_th_local_reduce_data_ack_reg[j] = 1'b1;
   end
   else 
   begin
      kmp_bambu_set_th_local_reduce_data_ack_reg[j] = 1'b0;
   end
   end
end

always @(*)
   begin
   for (i=0; i < PORTSIZE_kmp_bambu_get_th_local_reduce_data_ld; i = i + 1)
      begin
      if(kmp_bambu_get_th_local_reduce_data_ld[i] == 1)
      begin
         kmp_bambu_get_th_local_reduce_data_val_reg[i*BITSIZE_kmp_bambu_get_th_local_reduce_data_val +: BITSIZE_kmp_bambu_get_th_local_reduce_data_val] =  base_addr[kmp_bambu_get_th_local_reduce_data_tid[i*BITSIZE_kmp_bambu_get_th_local_reduce_data_tid +: BITSIZE_kmp_bambu_get_th_local_reduce_data_tid]*BITSIZE_kmp_bambu_get_th_local_reduce_data_val +: BITSIZE_kmp_bambu_get_th_local_reduce_data_val];
         kmp_bambu_get_th_local_reduce_data_ack_reg[i] = 1'b1;
      end
      else
      begin  
         kmp_bambu_get_th_local_reduce_data_val_reg[i*BITSIZE_kmp_bambu_get_th_local_reduce_data_val +: BITSIZE_kmp_bambu_get_th_local_reduce_data_val] = 0;                      
         kmp_bambu_get_th_local_reduce_data_ack_reg[i] = 1'b0;
      end
   end
end

always @(posedge clock 1RESET_EDGE) 
begin
   if (1RESET_VALUE)
   begin
      base_addr <= 1'b0;
      kmp_bambu_get_th_local_reduce_data_ack_old <= 1'b0;
      kmp_bambu_set_th_local_reduce_data_ack_old <= 1'b0;
      kmp_bambu_get_th_local_reduce_data_val_old <= 1'b0;
   end
   else
   begin
      base_addr <= base_addr_next;
      kmp_bambu_get_th_local_reduce_data_ack_old <= kmp_bambu_get_th_local_reduce_data_ack_reg;
      kmp_bambu_set_th_local_reduce_data_ack_old <= kmp_bambu_set_th_local_reduce_data_ack_reg;
      kmp_bambu_get_th_local_reduce_data_val_old <= kmp_bambu_get_th_local_reduce_data_val_reg;
   end
end

assign kmp_bambu_get_th_local_reduce_data_ack = kmp_bambu_get_th_local_reduce_data_ack_old;
assign kmp_bambu_set_th_local_reduce_data_ack = kmp_bambu_set_th_local_reduce_data_ack_old;
assign kmp_bambu_get_th_local_reduce_data_val = kmp_bambu_get_th_local_reduce_data_val_old;

wire mem;
generate 
  if(FORK_CALL_ID_END == FORK_CALL_ID_START)
  begin
    assign mem = ((ROOT_SPACE_ALIGNMENT == 0 || Mout_addr_ram[ROOT_SPACE_ALIGNMENT] == 1) && (Mout_addr_ram < EXTERNAL_BASE_ADDRESS)) ? 1'b0 : 1'b1; 
  end
  else 
  begin
    assign mem = ((ROOT_SPACE_ALIGNMENT == 0 || Mout_addr_ram[ROOT_SPACE_ALIGNMENT] == 1) && (Mout_addr_ram < EXTERNAL_BASE_ADDRESS) && (Mout_addr_ram[FORK_CALL_ID_END - 1: FORK_CALL_ID_START] == FORK_NUMBER)) ? 1'b0 : 1'b1; 
  end
endgenerate

assign Mout_oe_ram_memory = mem ? Mout_oe_ram : 1'b0;
assign Mout_oe_ram_local = mem ? 1'b0 : Mout_oe_ram;  
assign Mout_we_ram_memory = mem ? Mout_we_ram : 1'b0;
assign Mout_we_ram_local = mem ? 1'b0 : Mout_we_ram; 
assign Mout_addr_ram_memory = mem ? Mout_addr_ram : {BITSIZE_Mout_addr_ram{1'b0}};
assign Mout_addr_ram_local= mem ? {BITSIZE_Mout_addr_ram{1'b0}} : Mout_addr_ram;
assign Mout_Wdata_ram_memory = mem ? Mout_Wdata_ram : {BITSIZE_Mout_Wdata_ram{1'b0}};
assign Mout_Wdata_ram_local = mem ? {BITSIZE_Mout_Wdata_ram{1'b0}} : Mout_Wdata_ram;
assign Mout_data_ram_size_memory = mem ? Mout_data_ram_size : {BITSIZE_Mout_data_ram_size{1'b0}};
assign Mout_data_ram_size_local = mem ? {BITSIZE_Mout_data_ram_size{1'b0}} : Mout_data_ram_size;

generate 
  if(INNER_TAG == 1)
  begin    
    assign Mout_tag_memory = mem ? Mout_tag : {BITSIZE_Mout_tag{1'b0}};
    assign Mout_tag_local = mem ? {BITSIZE_Mout_tag{1'b0}} : Mout_tag;
  end
  else
  begin
    assign Mout_tag_memory = {BITSIZE_Mout_tag{1'b0}};
    assign Mout_tag_local = {BITSIZE_Mout_tag{1'b0}};
  end
endgenerate

assign M_DataRdy = M_DataRdy_memory || M_DataRdy_local;
assign M_Rdata_ram = M_DataRdy_memory ? M_Rdata_ram_memory : M_Rdata_ram_local;
assign M_back_pressure_local = M_DataRdy_memory && M_DataRdy_local;
generate 
  if(INNER_TAG == 1)
  begin      
    assign M_tag = M_DataRdy_memory ? M_tag_memory : M_tag_local;
  end
  else
  begin
    assign M_tag = {BITSIZE_M_tag{1'b0}};
  end
endgenerate

reg Mout_oe_ram_temp;
reg Mout_we_ram_temp;
reg [BITSIZE_Mout_addr_ram_memory-1:0] Mout_addr_ram_memory_temp;
reg [BITSIZE_Mout_Wdata_ram-1:0] Mout_Wdata_ram_temp;
reg [BITSIZE_Mout_data_ram_size-1:0] Mout_data_ram_size_temp;
reg [BITSIZE_Mout_tag-1:0] Mout_tag_temp;

generate
   if(USE_CS)
   begin
      wire register_valid;
      reg register_valid_reg;
      wire fifo_wr;
      wire fifo_rd;
      reg fifo_rd_reg;
      wire fifo_empty;
      wire fifo_empty_next;
      wire [BITSIZE_Mout_addr_ram+BITSIZE_Mout_Wdata_ram+BITSIZE_Mout_data_ram_size+BITSIZE_Mout_tag : 0] fifo_data_out;

      simple_fifo #(.ADDR_WIDTH(CONTEXT_NUMBER_SIZE),
      .BITSIZE_data_in(1+BITSIZE_Mout_addr_ram+BITSIZE_Mout_Wdata_ram+BITSIZE_Mout_data_ram_size+BITSIZE_Mout_tag),
      .BITSIZE_data_out(1+BITSIZE_Mout_addr_ram+BITSIZE_Mout_Wdata_ram+BITSIZE_Mout_data_ram_size+BITSIZE_Mout_tag)) fifo (.clock(clock),
      .reset(reset),
      .data_in({Mout_oe_ram,Mout_addr_ram,Mout_Wdata_ram,Mout_data_ram_size,Mout_tag}),
      .data_out(fifo_data_out),
      .empty(fifo_empty),
      .rd_en(fifo_rd),
      .wr_en(fifo_wr));

      assign register_valid = (Mout_back_pressure_memory && (Mout_oe_ram_memory || Mout_we_ram_memory));
      assign fifo_wr = (Mout_oe_ram || Mout_we_ram);
      assign fifo_rd = (fifo_wr || !fifo_empty) && !register_valid;
      assign Mout_back_pressure = 0;

      always @(posedge clock)
      begin
         if(1RESET_VALUE)
         begin
            register_valid_reg <= 0;
            fifo_rd_reg <= 0;
         end 
         else 
         begin
            register_valid_reg <= register_valid;
            fifo_rd_reg <= fifo_rd;
         end
      end

      always @(*)
      begin
         if(register_valid_reg || fifo_rd_reg)
         begin
            Mout_oe_ram_temp = fifo_data_out[BITSIZE_Mout_addr_ram+BITSIZE_Mout_Wdata_ram+BITSIZE_Mout_data_ram_size+BITSIZE_Mout_tag] == 1;
            Mout_we_ram_temp = fifo_data_out[BITSIZE_Mout_addr_ram+BITSIZE_Mout_Wdata_ram+BITSIZE_Mout_data_ram_size+BITSIZE_Mout_tag] == 0;
            Mout_addr_ram_memory_temp = fifo_data_out[BITSIZE_Mout_addr_ram+BITSIZE_Mout_Wdata_ram+BITSIZE_Mout_data_ram_size+BITSIZE_Mout_tag-1:BITSIZE_Mout_Wdata_ram+BITSIZE_Mout_data_ram_size+BITSIZE_Mout_tag];
            Mout_Wdata_ram_temp = fifo_data_out[BITSIZE_Mout_Wdata_ram+BITSIZE_Mout_data_ram_size+BITSIZE_Mout_tag-1:BITSIZE_Mout_data_ram_size+BITSIZE_Mout_tag];
            Mout_data_ram_size_temp = fifo_data_out[BITSIZE_Mout_data_ram_size+BITSIZE_Mout_tag-1:BITSIZE_Mout_tag];
            Mout_tag_temp = fifo_data_out[BITSIZE_Mout_tag-1:0];
         end
         else
         begin
            Mout_oe_ram_temp = 0;
            Mout_we_ram_temp = 0;
            Mout_addr_ram_memory_temp = 0;
            Mout_Wdata_ram_temp = 0;
            Mout_data_ram_size_temp = 0;
            Mout_tag_temp = 0;
         end
      end
   end
   else
   begin

      assign Mout_back_pressure = Mout_back_pressure_memory;

      always @(*) 
      begin
         Mout_oe_ram_temp = Mout_oe_ram;
         Mout_we_ram_temp = Mout_we_ram;
         Mout_addr_ram_memory_temp = Mout_addr_ram;
         Mout_Wdata_ram_temp = Mout_Wdata_ram;
         Mout_data_ram_size_temp = Mout_data_ram_size;
         Mout_tag_temp = Mout_tag;
      end
   end
endgenerate

generate 
   if(USE_FILTER==1)
   begin
      kmp_bambu_memory_filter_in #(.INNER_TAG(INNER_TAG),
      .BITSIZE_M_Rdata_ram_memory(BITSIZE_M_Rdata_ram_memory),
      .BITSIZE_M_Rdata_ram_local(BITSIZE_M_Rdata_ram_local),
      .BITSIZE_M_Rdata_ram(BITSIZE_M_Rdata_ram),
      .BITSIZE_M_tag_memory(BITSIZE_M_tag_memory),
      .BITSIZE_M_tag_local(BITSIZE_M_tag_local),
      .BITSIZE_M_tag(BITSIZE_M_tag)) filter_in (.M_Rdata_ram(M_Rdata_ram),
      .M_DataRdy(M_DataRdy),
      .M_tag(M_tag),
      .M_Rdata_ram_memory(M_Rdata_ram_memory),
      .M_DataRdy_memory(M_DataRdy_memory),
      .M_tag_memory(M_tag_memory),
      .M_Rdata_ram_local(M_Rdata_ram_local),
      .M_DataRdy_local(M_DataRdy_local),
      .M_tag_local(M_tag_local),
      .M_back_pressure_local(M_back_pressure_local));
      kmp_bambu_memory_filter_out #(.INNER_TAG(INNER_TAG),
      .ROOT_SPACE_ALIGNMENT(ROOT_SPACE_ALIGNMENT),
      .EXTERNAL_BASE_ADDRESS(EXTERNAL_BASE_ADDRESS),
      .FORK_CALL_ID_START(FORK_CALL_ID_START),
      .FORK_CALL_ID_END(FORK_CALL_ID_END),
      .FORK_NUMBER(FORK_NUMBER),
      .BITSIZE_Mout_addr_ram(BITSIZE_Mout_addr_ram),
      .BITSIZE_Mout_Wdata_ram(BITSIZE_Mout_Wdata_ram),
      .BITSIZE_Mout_data_ram_size(BITSIZE_Mout_data_ram_size),
      .BITSIZE_Mout_tag(BITSIZE_Mout_tag),
      .BITSIZE_Mout_addr_ram_memory(BITSIZE_Mout_addr_ram_memory),
      .BITSIZE_Mout_Wdata_ram_memory(BITSIZE_Mout_Wdata_ram_memory),
      .BITSIZE_Mout_data_ram_size_memory(BITSIZE_Mout_data_ram_size_memory),
      .BITSIZE_Mout_tag_memory(BITSIZE_Mout_tag_memory),
      .BITSIZE_Mout_addr_ram_local(BITSIZE_Mout_addr_ram_local),
      .BITSIZE_Mout_Wdata_ram_local(BITSIZE_Mout_Wdata_ram_local),
      .BITSIZE_Mout_data_ram_size_local(BITSIZE_Mout_data_ram_size_local),
      .BITSIZE_Mout_tag_local(BITSIZE_Mout_tag_local)) filter_out (.Mout_oe_ram_memory(Mout_oe_ram_memory),
      .Mout_we_ram_memory(Mout_we_ram_memory),
      .Mout_addr_ram_memory(Mout_addr_ram_memory),
      .Mout_Wdata_ram_memory(Mout_Wdata_ram_memory),
      .Mout_data_ram_size_memory(Mout_data_ram_size_memory),
      .Mout_tag_memory(Mout_tag_memory),
      .Mout_oe_ram_local(Mout_oe_ram_local),
      .Mout_we_ram_local(Mout_we_ram_local),
      .Mout_addr_ram_local(Mout_addr_ram_local),
      .Mout_Wdata_ram_local(Mout_Wdata_ram_local),
      .Mout_data_ram_size_local(Mout_data_ram_size_local),
      .Mout_tag_local(Mout_tag_local),
      .Mout_oe_ram(Mout_oe_ram_temp),
      .Mout_we_ram(Mout_we_ram_temp),
      .Mout_addr_ram(Mout_addr_ram_memory_temp),
      .Mout_Wdata_ram(Mout_Wdata_ram_temp),
      .Mout_data_ram_size(Mout_data_ram_size_temp),
      .Mout_tag(Mout_tag_temp));
   end
   else
   begin
      assign M_DataRdy = M_DataRdy_memory;
      assign M_Rdata_ram = M_Rdata_ram_memory;
      assign M_tag = M_tag_memory;
      assign Mout_oe_ram_memory = Mout_oe_ram_temp;
      assign Mout_we_ram_memory = Mout_we_ram_temp;
      assign Mout_addr_ram_memory =  Mout_addr_ram_memory_temp;
      assign Mout_Wdata_ram_memory =  Mout_Wdata_ram_temp;
      assign Mout_data_ram_size_memory = Mout_data_ram_size_temp;
      assign Mout_tag_memory = Mout_tag_temp;
      assign M_back_pressure_local = 1'b0;  
      assign Mout_oe_ram_local = 1'b0;  
      assign Mout_we_ram_local = 1'b0; 
      assign Mout_addr_ram_local = {BITSIZE_Mout_addr_ram{1'b0}}; 
      assign Mout_Wdata_ram_local = {BITSIZE_Mout_Wdata_ram{1'b0}}; 
      assign Mout_data_ram_size_local = {BITSIZE_Mout_data_ram_size{1'b0}}; 
      assign Mout_tag_local = {BITSIZE_Mout_tag_local{1'b0}}; 
   end
endgenerate

parameter RAM_DEPTH = (1 << ADDR_WIDTH);

reg [ADDR_WIDTH-1:0] wr_pointer;
reg [ADDR_WIDTH-1:0] wr_pointer_next;
reg [ADDR_WIDTH-1:0] rd_pointer;
reg [ADDR_WIDTH-1:0] rd_pointer_next;
reg [ADDR_WIDTH :0] status_cnt_reg;
wire [BITSIZE_data_in-1:0] data_ram ;

assign empty = status_cnt_reg == 0;

always @(posedge clock 1RESET_EDGE)
begin : WRITE_POINTER
  if(1RESET_VALUE) 
  begin
    wr_pointer = 0;
  end 
  else 
  begin
    wr_pointer = wr_pointer_next;
  end
end

always @(*)
begin
  if(wr_en)
  begin
    wr_pointer_next = wr_pointer + 1;
  end
  else
  begin
    wr_pointer_next = wr_pointer;
  end
end

always @(posedge clock 1RESET_EDGE)
begin : READ_POINTER
  if(1RESET_VALUE) 
  begin
    rd_pointer = 0;
  end 
  else
  begin
    rd_pointer = rd_pointer_next;
  end
end

always @(*)
begin
  if(rd_en)
  begin
    rd_pointer_next = rd_pointer + 1;
  end
  else
  begin
    rd_pointer_next = rd_pointer;
  end
end

always @(posedge clock 1RESET_EDGE)
begin : STATUS_COUNTER
  if(1RESET_VALUE) 
  begin
    status_cnt_reg <= 0;
  end 
  else if (rd_en && !wr_en  && (status_cnt_reg != 0)) 
  begin
    status_cnt_reg <= status_cnt_reg - 1;
  end 
  else if (wr_en && !rd_en && (status_cnt_reg != RAM_DEPTH)) 
  begin
    status_cnt_reg <= status_cnt_reg + 1;
  end
end

STD_SDP_BRAMFW #(
  .BITSIZE_address_inr(ADDR_WIDTH),
  .BITSIZE_address_inw(ADDR_WIDTH),
  .BITSIZE_data_in(BITSIZE_data_in),
  .BITSIZE_data_out(BITSIZE_data_out),
  .MEMORY_INIT_file(""),
  .n_elements(RAM_DEPTH),
  .READ_ONLY_MEMORY(0),
  .HIGH_LATENCY(0)
  ) BRAM (
  .clock(clock),
  .write_enable(wr_en),
  .address_inr(rd_pointer_next),
  .address_inw(wr_pointer_next),
  .data_in(data_in),
  .data_out(data_out));
